// ─── i18n Engine ───────────────────────────────────────────────
const i18n = {
  lang: 'de',

  init() {
    const urlLang = new URLSearchParams(window.location.search).get('lang');
    const storedLang = localStorage.getItem('t24_lang');
    const browserLang = (navigator.language || 'de').slice(0, 2).toLowerCase();
    const chosen = [urlLang, storedLang, browserLang, 'de'].find(c => c && I18N[c]) || 'de';
    this.setLang(chosen, false);
  },

  setLang(lang, updateUrl = true) {
    if (!I18N[lang]) lang = 'de';
    this.lang = lang;
    const t = I18N[lang];
    document.documentElement.dir = t.dir;
    document.documentElement.lang = lang;
    localStorage.setItem('t24_lang', lang);
    if (updateUrl) {
      const url = new URL(window.location);
      url.searchParams.set('lang', lang);
      window.history.replaceState({}, '', url);
    }
    const ddBtn = document.getElementById('langDropdownBtn');
    if (ddBtn) ddBtn.textContent = `${t.flag} ${lang.toUpperCase()} ▼`;
    document.querySelectorAll('[data-i18n]').forEach(el => {
      const key = el.getAttribute('data-i18n');
      if (t[key] !== undefined) {
        if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') el.placeholder = t[key];
        else el.textContent = t[key];
      }
    });
    document.querySelectorAll('[data-i18n-html]').forEach(el => {
      const key = el.getAttribute('data-i18n-html');
      if (t[key] !== undefined) el.innerHTML = t[key];
    });
    document.querySelectorAll('[data-i18n-title]').forEach(el => {
      const key = el.getAttribute('data-i18n-title');
      if (t[key] !== undefined) el.title = t[key];
    });
    document.querySelectorAll('[data-i18n-aria]').forEach(el => {
      const key = el.getAttribute('data-i18n-aria');
      if (t[key] !== undefined) el.setAttribute('aria-label', t[key]);
    });
    document.dispatchEvent(new CustomEvent('i18n:changed', { detail: { lang, t } }));
  },

  t(key) {
    return I18N[this.lang]?.[key] ?? I18N['de']?.[key] ?? key;
  },

  buildDropdown() {
    const t = I18N[this.lang];
    return `<div class="lang-dropdown-wrap">
      <button class="lang-btn" id="langDropdownBtn" onclick="i18n.toggleDropdown()" aria-haspopup="listbox" aria-expanded="false">
        ${t.flag} ${this.lang.toUpperCase()} ▼
      </button>
      <ul class="lang-menu" id="langMenu" role="listbox">
        ${Object.values(I18N).map(l => `<li role="option" aria-selected="${l.lang===this.lang}" onclick="i18n.setLang('${l.lang}');i18n.closeDropdown()">${l.flag} ${l.label}</li>`).join('')}
      </ul>
    </div>`;
  },

  toggleDropdown() {
    const menu = document.getElementById('langMenu');
    const btn = document.getElementById('langDropdownBtn');
    const open = menu.classList.toggle('open');
    btn.setAttribute('aria-expanded', open);
  },

  closeDropdown() {
    const menu = document.getElementById('langMenu');
    const btn = document.getElementById('langDropdownBtn');
    if (menu) menu.classList.remove('open');
    if (btn) btn.setAttribute('aria-expanded', 'false');
  },

  injectStyles() {
    if (document.getElementById('i18n-styles')) return;
    const style = document.createElement('style');
    style.id = 'i18n-styles';
    style.textContent = `
      .lang-dropdown-wrap{position:relative;flex-shrink:0;}
      .lang-btn{display:flex;align-items:center;gap:5px;padding:6px 12px;border:1px solid var(--border);border-radius:8px;background:var(--surface);cursor:pointer;font-family:system-ui,sans-serif;font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;transition:all 0.18s ease;}
      .lang-btn:hover{border-color:var(--blue-bright);color:var(--blue-bright);}
      .lang-menu{display:none;position:absolute;top:calc(100% + 6px);right:0;background:var(--surface);border:1px solid var(--border);border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,0.12);list-style:none;padding:6px;min-width:160px;z-index:500;max-height:320px;overflow-y:auto;}
      [dir="rtl"] .lang-menu{right:auto;left:0;}
      .lang-menu.open{display:block;}
      .lang-menu li{display:flex;align-items:center;gap:8px;padding:8px 12px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:500;transition:background 0.15s ease;}
      .lang-menu li:hover{background:var(--bg-deep);}
      .lang-menu li[aria-selected="true"]{color:var(--blue-bright);background:var(--blue-soft);}
    `;
    document.head.appendChild(style);
  },
};

document.addEventListener('click', e => {
  if (!e.target.closest('.lang-dropdown-wrap')) i18n.closeDropdown();
});
